name: Deploy to uncommentCronOfLentraPush

on:
  push:
    branches:
      - uncommentCronOfLentraPush
  workflow_dispatch:

jobs:
  deploy:
    runs-on: [self-hosted, jenkins-server]

    steps:
      - name: Checkout code
        uses: actions/checkout@v4


      - name: Run remote script
        run: |
          ssh -o StrictHostKeyChecking=no ubuntu@10.1.106.143 << 'EOF'
            #!/bin/bash
            set -e  # Exit immediately if a command exits with a non-zero status
            set -x  # Print commands and their arguments as they are executed

            echo "Starting deployment to uncommentCronOfLentraPush environment"

            echo "Navigating to node_crm directory"
            cd /home/ubuntu/api_code/ramfincorp-backend-Lentra
            echo "Pulling latest changes from uncommentCronOfLentraPush branch"
            git reset --hard origin/uncommentCronOfLentraPush
            git pull origin uncommentCronOfLentraPush
            echo "Installing npm dependencies"
            npm install
            npm run build 
            echo "Displaying last 10 git commits"
            git log | head -10

            echo "Navigating to common-module directory"
            cd /home/ubuntu/api_code/ramfincorp-backend-Lentra/src/common/common-module
            echo "Resetting to origin/master"
            git reset --hard origin/master
            echo "Checking out master branch"
            git checkout master
            echo "Pulling latest changes for common-module"
            git pull origin master

            echo "Restarting node-crm-master service with pm2"
            pm2 restart ramfincorp-backend-Lentra
            echo "Displaying last 15 git commits for common-module"
            git log | head -15

            echo "Deployment to master completed successfully"
          EOF



name: PR Check

on:
  pull_request:
    branches:
      - pre-prod

jobs:
  lint-and-scan:
    runs-on: ubuntu-latest
    steps:
      - name: Checkout code
        uses: actions/checkout@v4
      - name: Set up Node.js
        uses: actions/setup-node@v5
        with:
          node-version: '22'
      - name: Install dependencies
        run: npm install
      - name: Run Prettier check
        run: npx prettier --check .

  build:
    runs-on: ubuntu-latest
    needs: lint-and-scan
    steps:
      - name: Checkout code
        uses: actions/checkout@v4
      - name: Docker build
        run: docker build -t ramfincorp-backend .



name: Preprod Deployment

on:
  pull_request:
    types: 
      - opened
      - synchronize
      - closed
    branches:
      - pre-prod

env:
  AWS_REGION: ap-south-1
  ECR_REPOSITORY: ramfincorp/ramfincorp-backend
  BASE_PATH: /home/ubuntu/preprod/ramfincorp-backend
  SERVICE_NAME: ramfincorp-backend
  GIT_BRANCH: pre-prod

jobs:
  build:
    if: github.event.pull_request.merged == true || github.event.pull_request.state == 'open'
    runs-on: [self-hosted, ramfin]
    outputs:
      IMAGE_TAG: ${{ steps.set_tag.outputs.IMAGE_TAG }}
      IS_PR: ${{ steps.check_pr.outputs.IS_PR }}
      ENV_NAME: ${{ steps.check_pr.outputs.ENV_NAME }}

    steps:
      - name: Check if PR
        id: check_pr
        run: |
          if [[ "${{ github.event.action }}" == "closed" && "${{ github.event.pull_request.merged }}" == "true" ]]; then
            echo "IS_PR=false" >> $GITHUB_OUTPUT
            echo "ENV_NAME=preprod" >> $GITHUB_OUTPUT
          else
            echo "IS_PR=true" >> $GITHUB_OUTPUT
            echo "ENV_NAME=dev" >> $GITHUB_OUTPUT
          fi

      - name: Set image tag
        id: set_tag
        run: |
          if [[ "${{ github.event.action }}" == "closed" && "${{ github.event.pull_request.merged }}" == "true" ]]; then
            echo "IMAGE_TAG=1.${{ github.run_number }}" >> $GITHUB_OUTPUT
          else
            echo "IMAGE_TAG=1.${{ github.run_number }}-pr-${{ github.event.pull_request.number }}" >> $GITHUB_OUTPUT
          fi

      - name: Configure AWS credentials
        uses: aws-actions/configure-aws-credentials@v2
        with:
          aws-region: ${{ env.AWS_REGION }}
          role-to-assume: ${{ secrets.AWS_ROLE_ARN }}

      - name: Login to Amazon ECR
        shell: bash
        run: |
          aws ecr get-login-password --region ${{ env.AWS_REGION }} \
          | docker login --username AWS --password-stdin 361795871686.dkr.ecr.${{ env.AWS_REGION }}.amazonaws.com

      - name: Checkout code
        run: |
          cd ${{ env.BASE_PATH }}
          git reset --hard HEAD
          git clean -fd
          git fetch origin
          if [[ "${{ github.event.action }}" == "closed" && "${{ github.event.pull_request.merged }}" == "true" ]]; then
            git checkout ${{ env.GIT_BRANCH }}
            git pull origin ${{ env.GIT_BRANCH }}
          else
            git checkout ${{ github.head_ref }}
            git pull origin ${{ github.head_ref }}
          fi

          cd ${{ env.BASE_PATH }}/src/common/common-module
          git checkout master
          git pull origin master

      - name: Build and Push Docker image
        shell: bash
        run: |
          cd ${{ env.BASE_PATH }}
          IMAGE_NAME=361795871686.dkr.ecr.${{ env.AWS_REGION }}.amazonaws.com/${{ env.ECR_REPOSITORY }}:${{ steps.set_tag.outputs.IMAGE_TAG }}

          echo "Building Image: ${IMAGE_NAME}"
          docker build \
          -t "${IMAGE_NAME}" \
          --platform linux/amd64 \
          -f Dockerfile .

          echo "Pushing image: ${IMAGE_NAME}"
          docker push "${IMAGE_NAME}"

      - name: Create and push git release tag
        if: github.event.action == 'closed' && github.event.pull_request.merged == true
        run: |
          cd ${{ env.BASE_PATH }}
          TAG_NAME="${{ steps.set_tag.outputs.IMAGE_TAG }}"
          echo "Creating and pushing git tag: ${TAG_NAME}"
          git tag "${TAG_NAME}"
          git push origin "${TAG_NAME}"

  deploy:
    needs: build
    name: Deploy
    if: github.event.pull_request.merged == true || github.event.pull_request.state == 'open'
    runs-on: [self-hosted, ramfin]
    env:
      ENV_NAME: ${{ needs.build.outputs.ENV_NAME }}
    steps:
      - name: Checkout code
        run: |
          cd ${{ env.BASE_PATH }}
          git reset --hard HEAD
          git clean -fd
          git fetch origin
          if [[ "${{ needs.build.outputs.IS_PR }}" == "true" ]]; then
            git checkout ${{ github.head_ref }}
            git pull origin ${{ github.head_ref }}
          else
            git checkout ${{ env.GIT_BRANCH }}
            git pull origin ${{ env.GIT_BRANCH }}
          fi

      - name: Configure AWS credentials
        uses: aws-actions/configure-aws-credentials@v2
        with:
          aws-access-key-id: ${{ secrets.RF_DEV_ACCESS_KEY }}
          aws-secret-access-key: ${{ secrets.RF_DEV_ACCESS_SECRET }}
          aws-region: ${{ env.AWS_REGION }}

      - name: Verify Kubernetes Context
        run: |
          if [[ "${{ needs.build.outputs.IS_PR }}" == "true" ]]; then
            CONTEXT="arn:aws:eks:ap-south-1:361795871686:cluster/rf-dev-eks-cluster"
          else
            CONTEXT="arn:aws:eks:ap-south-1:361795871686:cluster/pre-prod-eks-cluster"
          fi
          kubectl config use-context "${CONTEXT}"
          if ! kubectl cluster-info > /dev/null 2>&1; then
            echo "Error: Could not connect to the Kubernetes cluster context."
            exit 1
          fi

      - name: Deploy using deploy.sh
        run: |
          cd ${{ env.BASE_PATH }}/cicd
          chmod +x deploy.sh
          if [[ "${{ needs.build.outputs.IS_PR }}" == "true" ]]; then
            NAMESPACE="${{ env.SERVICE_NAME }}-pr-${{ github.event.pull_request.number }}"
          else
            NAMESPACE="${{ env.SERVICE_NAME }}-integration"
          fi
          ./deploy.sh ${{ env.SERVICE_NAME }} ${{ needs.build.outputs.IMAGE_TAG }} "${NAMESPACE}"



