# Cross-platform TTY check
if [ -e "/dev/tty" ]; then
  TTY_OUTPUT="/dev/tty"
else
  TTY_OUTPUT="/dev/stdout"
fi
echo "────────────────────────────────────────" > "$TTY_OUTPUT"
echo "▶ Pre-commit validation started..." > "$TTY_OUTPUT"

# Run lint-staged
if ! command -v npx > /dev/null || ! npx --no-install lint-staged --version > /dev/null 2>&1; then
  echo "✗ 'lint-staged' is not installed or not configured. Please install and configure it before committing." > "$TTY_OUTPUT"
  exit 1
fi

npm run lint-staged > /dev/null 2>&1
if [ $? -ne 0 ]; then
  echo "✗ Lint-staged checks failed - please fix issues" > "$TTY_OUTPUT"
  npm run lint-staged > "$TTY_OUTPUT" 2>&1  # Show output on failure
  exit 1
else
  echo "✓ Lint-staged passed" > "$TTY_OUTPUT"
fi

# Type check
npm run typecheck > /dev/null 2>&1
if [ $? -ne 0 ]; then
  echo "✗ Type validation failed - please resolve type errors" > "$TTY_OUTPUT"
  npm run typecheck > "$TTY_OUTPUT" 2>&1  # Show output on failure
  exit 1
else
  echo "✓ Type checking passed" > "$TTY_OUTPUT"
fi

echo "✓ All checks passed. Committing..." > "$TTY_OUTPUT"
exit 0







apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ .Values.name }}
  namespace: {{ .Release.Namespace }}
spec:
  replicas: {{ .Values.replicaCount }}
  selector:
    matchLabels:
      app: {{ .Values.name }}
  template:
    metadata:
      labels:
        app: {{ .Values.name }}
    spec:
      containers:
        - name: {{ .Values.name }}
          image: {{ .Values.image.repository }}:{{ .Values.image.tag }}
          imagePullPolicy: Always
          ports:
            - containerPort: {{ .Values.service.port }}
          volumeMounts:
            - name: env-secret
              mountPath: /app/.env
              subPath: .env
          env:
            - name: NODE_ENV
              value: "production"
          resources:
{{- toYaml .Values.resources | nindent 12 }}
      volumes:
        - name: env-secret
          secret:
            secretName: {{ .Values.envSecretName | default (printf "%s-env" .Values.name) }}



apiVersion: autoscaling/v2
kind: HorizontalPodAutoscaler
metadata:
  name: {{ .Values.name }}-hpa
  namespace: {{ .Release.Namespace }}
spec:
  scaleTargetRef:
    apiVersion: apps/v1
    kind: Deployment
    name: {{ .Values.name }}
  minReplicas: {{ .Values.replicaCount }}
  maxReplicas: 5
  metrics:
    - type: Resource
      resource:
        name: cpu
        target:
          type: Utilization
          averageUtilization: 70
    - type: Resource
      resource:
        name: memory
        target:
          type: Utilization
          averageUtilization: 80



apiVersion: gateway.networking.k8s.io/v1
kind: HTTPRoute
metadata:
  name: {{ .Values.name }}-route
  namespace: {{ .Release.Namespace }}
  labels:
    app: {{ .Values.name }}
spec:
  parentRefs:
  - name: {{ .Values.gateway.name }}
    namespace: {{ .Values.gateway.namespace | default .Values.namespace }}
  hostnames:
  {{- range .Values.gateway.hosts }}
  - {{ . | quote }}
  {{- end }}
  rules:
  - matches:
    - path:
        type: PathPrefix
        value: /
    backendRefs:
    - name: {{ .Values.service.name }}
      port: {{ .Values.service.port }}







apiVersion: v1
kind: Service
metadata:
  name: {{ .Values.service.name }}
  namespace: {{ .Release.Namespace }}
  labels:
    app: {{ .Values.name }}
    app.kubernetes.io/managed-by: "Helm"
  annotations:
    meta.helm.sh/release-name: {{ .Values.name }}
    meta.helm.sh/release-namespace: {{ .Release.Namespace }}
spec:
  selector:
    app: {{ .Values.name }}
  ports:
    - protocol: TCP
      port: 80
      targetPort: {{ .Values.service.port }}
  type: {{ .Values.service.type }}



apiVersion: v2
name: ramfincorp-backend
