                  stgOneHitId: resp.data.stgOneHitId,
                  stgTwoHitId: resp.data.stgTwoHitId,
                },
                'Question',
              )
            } else {
              throw new BadRequestError('Problem In Your Details: Contact Support')
            }
          } else if (response.data) {
