export type WhereQuery =
  | Partial
  | ((query: Knex.QueryBuilder) => any)
  | AlternateWhere[]
⋮----
export type UpdateQuery = Partial
⋮----
export type SelectFields = T[] | ['*']
⋮----
type SortItem =
  | T
  | { column: T; order?: 'asc' | 'desc'; nulls?: 'first' | 'last' }
⋮----
export type SortCriteria = SortItem[]
⋮----
export type InsertData = T
⋮----
export type DeleteWhere = {
  column: T
  operator?: string
  value: string | number | boolean
}[]
⋮----
export type AlternateWhere = {
  [K in keyof T]: {
    column: K
    operator?: string
    value: T[K]
  }
}[keyof T]
⋮----
export type WhereIn = { column: T; value: string[] | number[] | boolean[] }
⋮----
export type WhereRaw = {
  rawQuery: string
  values: string[] | number[] | boolean[]
}
⋮----
export type WhereNotNull = T[]
export type WhereNot = WhereQuery
export type Paginate = { page: number; perPage: number }
⋮----
export type KnexFindParams = {
  where?: WhereQuery
  select?: SelectFields
  order?: SortCriteria
  whereIn?: WhereIn[]
  whereRaw?: WhereRaw[]
  whereNotNull?: WhereNotNull
  whereNot?: WhereNot
  paginate?: Paginate
  sum?: SelectFields
}
