                        year: 'numeric' , month: 'long' , day: 'numeric' , hour: '2-digit' , minute: '2-digit' }) %>


            <% if (transaction.processed_at) { %>


                    Processed Date:

                        <%= new Date(transaction.processed_at).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' ,
                            year: 'numeric' , month: 'long' , day: 'numeric' , hour: '2-digit' , minute: '2-digit' }) %>


                <% } %>


                        Payment Gateway:

                            <%= transaction.payment_gateway || 'RAZORPAY' %>


                    <% if (transaction.gateway_reference_id) { %>


                            Gateway Reference ID:

                                <%= transaction.gateway_reference_id %>


                        <% } %>






Customer Information


                Customer ID:

                    <%= customer.customerID %>




                Name:

                    <%= customer.name %>




                Mobile:

                    <%= customer.mobile %>




                Email:

                    <%= customer.email %>








Amount Details




                    Gross Withdrawal Amount:
                    ₹
                        <%= parseFloat(transaction.amount).toLocaleString('en-IN', { minimumFractionDigits: 2 }) %>




                    TDS Deducted (10%):
                    - ₹
                        <%= parseFloat(transaction.tds_amount || 0).toLocaleString('en-IN', { minimumFractionDigits: 2
                            }) %>




                    Net Amount Transferred:
                    ₹
                        <%= parseFloat(transaction.net_amount).toLocaleString('en-IN', { minimumFractionDigits: 2 }) %>






        <% if (bankAccount) { %>



Bank Account Details




                        Account Holder Name:

                            <%= bankAccount.bank_holder_name %>




                        Bank Name:

                            <%= bankAccount.bank %>




                        Account Number:
                        ****<%= bankAccount.accountNo.slice(-4) %>



                        IFSC Code:

                            <%= bankAccount.bankIfsc %>




            <% } %>





Important Information:


                        • This receipt is generated electronically and is valid without signature.

                        • TDS certificate will be provided at the end of financial year.

                        • For any queries, please contact our customer support with this transaction ID.

