# #!/bin/bash

# # Navigate to the dist directory
# cd dist

# # Find and replace import statements in JavaScript files
# find . -type f -name "*.js" -exec sed -i 's/"@\/\([^"]*\)"/"\.\/\1.js"/g' {} +

# # Navigate back to the project root directory
# cd ..

#!/bin/bash

# Navigate to the dist directory
cd dist

# Find and replace import statements in JavaScript files
find . -type f -name "*.js" -exec sed -i -E 's/"(@\/[^"]*)"/"\1.js"/;t;d' {} +
find . -type f -name "*.js" -exec sed -i -E 's/"(\.\/[^"]*)"/"\1.js"/;t;d' {} +

# Navigate back to the project root directory
cd ..



version: 0.0
os: linux

files:
  - source: /
    destination: /home/ubuntu/api_node/ramfincorp-backend

hooks:

  AfterInstall:
    - location: scripts/install_dependencies.sh
      timeout: 300
      runas: ubuntu

  ApplicationStart:
    - location: scripts/start_server.sh
      timeout: 300
      runas: ubuntu



version: '3.8'
services:
  app:
    container_name: app
    restart: always
    build: .
    command: npm run start
    volumes:
      - .:/usr/app
      - /usr/app/node_modules
    ports:
      - 8088:8088
    depends_on:
      - mongo
      - mysql
      - redis
  mongo:
    container_name: mongo
    image: mongo
    restart: always
    volumes:
      - $HOME/docker/volumes/mongo:/data/db
    ports:
      - 27017:27017
  mysql:
    container_name: mysql
    image: biarms/mysql:5.7.30
    restart: always
    environment:
      - MYSQL_ROOT_PASSWORD=password
    ports:
      - 3306:3306
  redis:
    image: redis
    ports:
      - '6379:6379'



FROM node:20.19.5 AS build

WORKDIR /app

COPY package*.json ./

RUN npm install

COPY . .

RUN npm run build

# Install Chromium and create chromium-browser symlink
RUN apt-get update && apt-get install -y chromium \
    && ln -s /usr/bin/chromium /usr/bin/chromium-browser \
    && rm -rf /var/lib/apt/lists/*

EXPOSE 8080

# # Start server in dev mode (nodemon) or prod mode (node)
CMD ["npm", "run", "start"]



