{
  "name": "ramfincorp-backend",
  "version": "0.0.0",
  "type": "commonjs",
  "description": "Express API Server",
  "author": "Ramfincorp",
  "license": "ISC",
  "scripts": {
    "start": "cross-env node dist/server.js",
    "dev": "cross-env NODE_ENV=development nodemon",
    "debug": "cross-env NODE_ENV=development nodemon --config nodemon.debug.json",
    "prod": "cross-env NODE_ENV=production nodemon",
    "staging": "cross-env NODE_ENV=staging nodemon",
    "preprod": "cross-env NODE_ENV=preprod nodemon",
    "build": "swc src -d dist --source-maps --copy-files",
    "build:tsc": "tsc && tsc-alias",
    "test": "jest --forceExit --detectOpenHandles",
    "lint": "eslint --ignore-path .gitignore --ext .ts src/",
    "lint:fix": "npm run lint -- --fix",
    "prisma:init": "prisma init",
    "prisma:migrate": "prisma migrate dev --preview-feature",
    "prisma:generate": "prisma generate",
    "deploy:prod": "npm run build && pm2 start ecosystem.config.js --only prod",
    "deploy:dev": "pm2 start ecosystem.config.js --only dev",
    "clean": "rm -rf dist",
    "prettier": "prettier --write .",
    "lint-staged": "npx lint-staged",
