# ramfincorp-backend

## Setup

#### 1. Requirements

- node.js >= 18.12.1
- npm >= 8.19.2 (`$ npm i -g npm`)

#### 2. Installation

- `$ git clone https://github.com/anshubeniwal/ramfincorp-backend.git`
- `$ cd ramfincorp-backend && npm install`

#### 3. Mysql

- `install mysql && configure`

#### 4. MongoDb

- `install mongodb && configure`

#### 5. Run

- ##### Development
  - go to `src/config/custom-environment-variables.ts` and make sure all the mentioned variables should be in .env file
  - configure .env
  - `$ npm run dev`

#### 6. Build

Project build will be stored under the directory `/ramfincorp-backend/dist`

- ##### Development
  - `$ npm start dev`

#### Common Issues

- ##### Failed while installing dependencies


saaaa

  - clear cache for NPM with `$ npm cache clean --force`
  - delete `node_modules`
  - re-install dependencies using `$ npm install`

- ##### Unable to setup or run
  - go to logs in logs file
  - debug the error
  - save changes
  - run project in development mode


## Development

Buid the image:

```
docker build -t app-backend --platform linux/amd64 .
docker tag app-backend:latest 361795871686.dkr.ecr.ap-south-1.amazonaws.com/ramfincorp/app-backend:1.0
docker rm -f app-backend

apt update && apt install -y default-mysql-client
docker run --name app-backend --net crm-net -p 9091:8080 -d app-backend

docker network create crm-net

docker run --name redis-host --net crm-net -d redis:7.0.15

kubectl apply -f deployment.yaml
```



tags:
  - name: users
    description: users API

paths:
  # [GET] users
  /users:
    get:
      tags:
        - users
      summary: Find All Users
      responses:
        200:
          description: 'OK'
        500:
          description: 'Server Error'

    # [POST] users
    post:
      tags:
        - users
      summary: Add User
      parameters:
        - name: body
          in: body
          description: user Data
          required: true
          schema:
            $ref: '#/definitions/users'
      responses:
        201:
          description: 'Created'
        400:
          description: 'Bad Request'
        409:
          description: 'Conflict'
        500:
          description: 'Server Error'

  # [GET] users/id
  /users/{id}:
    get:
      tags:
        - users
      summary: Find User By Id
      parameters:
        - name: id
          in: path
          description: User Id
          required: true
          type: integer
      responses:
        200:
          description: 'OK'
        409:
          description: 'Conflict'
        500:
          description: 'Server Error'

    # [PUT] users/id
    put:
      tags:
        - users
      summary: Update User By Id
      parameters:
        - name: id
          in: path
          description: user Id
          required: true
          type: integer
        - name: body
          in: body
          description: user Data
          required: true
          schema:
            $ref: '#/definitions/users'
      responses:
        200:
          description: 'OK'
        400:
          description: 'Bad Request'
        409:
          description: 'Conflict'
        500:
          description: 'Server Error'

    # [DELETE] users/id
    delete:
      tags:
        - users
      summary: Delete User By Id
      parameters:
        - name: id
          in: path
          description: user Id
          required: true
          type: integer
      responses:
        200:
          description: 'OK'
        409:
          description: 'Conflict'
        500:
          description: 'Server Error'

# definitions
definitions:
  users:
    type: object
    required:
      - email
      - password
    properties:
      email:
        type: string
        description: user Email
      password:
        type: string
        description: user Password

schemes:
  - https
  - http



{
  "compileOnSave": false,
  "compilerOptions": {
    "skipLibCheck": true,
    "types": [
      "node"
    ],
    "target": "es2017",
    "lib": [
      "es2017",
      "esnext.asynciterable",
      "dom"
    ],
    "typeRoots": [
      "node_modules/@types"
    ],
    "allowSyntheticDefaultImports": true,
    "experimentalDecorators": true,
    "emitDecoratorMetadata": true,
    "forceConsistentCasingInFileNames": true,
    "moduleResolution": "node",
    "module": "commonjs",
    "pretty": true,
    "sourceMap": true,
    "declaration": true,
    "rootDir": "src",
    "outDir": "dist",
    "allowJs": true,
    "noEmit": false,
    "esModuleInterop": true,
    "resolveJsonModule": true,
    "importHelpers": true,
    "baseUrl": "src",
    "paths": {
      "@/*": [
        "*"
      ],
      "@/helpers/*": [
        "helpers/*"
      ],
      "@/config/*": [
        "config/*"
      ],
      "@/controllers/*": [
        "controllers/*"
      ],
      "@/dtos/*": [
        "dtos/*"
      ],
      "@/exceptions/*": [
        "exceptions/*"
      ],
      "@/interfaces/*": [
        "interfaces/*"
      ],
      "@/middlewares/*": [
        "middlewares/*"
      ],
      "@/routes/*": [
        "routes/*"
      ],
      "@/services/*": [
        "services/*"
      ],
      "@/utils/*": [
        "utils/*"
      ],
      "@/database/*": [
        "database/*"
      ],
      "@/mysql/*": [
        "database/mysql/*"
      ]
    }
  },
  "include": [
    "src/**/*.ts",
    "src/**/*.json",
    ".env",
    "src/utils/config.server.ts",
    "config/config.js",
  ],
  "exclude": [
    "node_modules",
    "src/http",
    "src/logs",
    "src/tests"
  ]
}
